function fixTs(ts) {
  if (!ts || typeof ts !== 'string') return ts;
  ts = ts.replace('T', ' ').replace(/Z$/, '').trim();
  ts = ts.replace(/^(\d{4})/, (match, year) => {
    return parseInt(year) !== 2023 ? '2023' : year;
  });
  const m = ts.match(/^(\d{4}-\d{2}-\d{2}) (\d{2}):(\d{2}):(\d{2})$/);
  if (!m) return ts;
  const hour = parseInt(m[2]);
  if (hour < 24) return ts;
  const d = new Date(`${m[1]}T00:00:00`);
  d.setHours(hour);
  const date = d.toISOString().slice(0, 10);
  const h = String(d.getHours()).padStart(2, '0');
  return `${date} ${h}:${m[3]}:${m[4]}`;
}

const raw = $input.first().json.output
         || $input.first().json.text
         || "";

let c = raw.replace(/```json\s*/gi, "").replace(/```\s*/g, "").trim();
const s = c.indexOf("{");
const e = c.lastIndexOf("}");
if (s === -1 || e === -1) throw new Error("Kein JSON gefunden: " + c.substring(0, 200));

let p = {};
let parseSuccess = false;

try {
  p = JSON.parse(c.substring(s, e + 1));
  parseSuccess = true;
} catch (err) {
  const eventsMatch = c.match(/"events"\s*:\s*(\[[\s\S]*?\])/);
  const confidenceMatch = c.match(/"confidence_score"\s*:\s*([0-9.]+)/);
  const cotMatch = c.match(/"chain_of_thought"\s*:\s*"([\s\S]*?)"\s*,\s*"/);

  p.events = eventsMatch ? (() => { try { return JSON.parse(eventsMatch[1]); } catch { return []; } })() : [];
  p.confidence_score = confidenceMatch ? parseFloat(confidenceMatch[1]) : 0.0;
  p.chain_of_thought = cotMatch ? cotMatch[1] : "Fehler beim Parsen der CoT (durch n8n-Selbstheilung gerettet)";
}

if (!Array.isArray(p.events)) p.events = [];
if (typeof p.confidence_score !== "number") p.confidence_score = 0.0;

p.events = p.events.map(ev => ({
  ...ev,
  event_timestamp: fixTs(ev.event_timestamp)
}));

return [{ json: { ...p, error: !parseSuccess } }];

try {
  const disp = $('Clean-Dispatcher').first().json;

  // Falls der Dispatcher schon fehlerhaft war, leiten wir das direkt als Ablehnung weiter
  if (disp.error) {
    return [{ json: { ...disp, approved: false, reason: disp.reason } }];
  }

  const raw = $input.first().json.output || $input.first().json.text || "";
  let c = raw.replace(/```json\s*/gi, "").replace(/```\s*/g, "").trim();
  const s = c.indexOf("{"), e = c.lastIndexOf("}");

  if (s === -1 || e === -1) {
    return [{ json: { ...disp, approved: false, reason: "Compliance-Antwort ist kein gültiges JSON: " + c.substring(0, 100) } }];
  }

  const p = JSON.parse(c.substring(s, e + 1));
  if (typeof p.approved !== "boolean") p.approved = false;

  return [{ json: { ...disp, approved: p.approved, reason: p.reason || "Von Compliance abgelehnt." } }];
} catch (err) {
  const disp = $('Clean-Dispatcher').first().json;
  return [{ json: { ...disp, approved: false, reason: "Fehler in Compliance-Bereinigung: " + err.message } }];
}

const result = $input.first().json;
return [{ json: {
  chain_of_thought:           result.chain_of_thought,
  confidence_score:           result.confidence_score,
  events:                     result.events,
  error:                      false,
  approved:                   true,
  reason:                     result.reason,
  compliance_rejection_count: result.compliance_rejection_count ?? 0
}}];

const cur = $json;
const rejectionCount = (cur.compliance_rejection_count ?? 0) + 1;
return [{ json: { 
  ...cur, 
  last_rejection: cur.reason || "abgelehnt",
  compliance_rejection_count: rejectionCount
}}];

